question.sql:

  SELECT SUM(
      array_length(
          string_to_array(trim(both '[]' from votes), ','), 1
      )
  ) AS total_votes
  FROM scenicornot.locations l
  JOIN scenicornot.hexgrid10km h ON ST_Within(l.geom_bng, h.geom)
  GROUP BY h.cell_id
  ORDER BY total_votes DESC
  LIMIT 1;


  SELECT COUNT(DISTINCT cluster_id)
  FROM (
      SELECT ST_ClusterDBSCAN(geom, 15000, 4) OVER () AS cluster_id
      FROM quakes.scotquakes
  ) sub
  WHERE cluster_id IS NOT NULL;


  SELECT ST_Length(ST_MakeLine(geom ORDER BY datetime)::geography)
  FROM trajectory.tracking
  WHERE userid = 'p3';
